    "content": "<head>\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <style>\n    body {\n      background-color: white;\n      margin: 0;\n    }\n\n    .container {\n      position: relative;\n      text-align: center;\n    }\n\n    .restaurant-image {\n      width: 100%;\n      height: auto;\n      display: block;\n    }\n\n    .overlay-text {\n      position: absolute;\n      top: 50%;\n      left: 50%;\n      transform: translate(-50%, -50%);\n      color: white;\n      font-size: 2.5rem; /* Tamaño base más pequeño */\n      font-family: 'Georgia', serif;\n      background: rgba(0, 0, 0, 0.4);\n      padding: 0.5rem 1rem;\n      border-radius: 10px;\n      max-width: 90%;\n      box-sizing: border-box;\n      text-align: center;\n    }\n\n    footer {\n      background-color: white;\n      color: #333;\n      padding: 1rem;\n      text-align: center;\n      font-family: sans-serif;\n      font-size: 0.9rem;\n    }\n\n    /* Ajuste para pantallas pequeñas */\n    @media (max-width: 600px) {\n      .overlay-text {\n        font-size: 1.2rem; /* Mucho más pequeño en móvil */\n        padding: 0.5rem;\n      }\n    }\n  </style>\n</head>\n\n<body>\n  <div class=\"container\">\n    <img \n      alt=\"Imagen de Restaurante\" \n      src=\"https://lh3.googleusercontent.com/pw/AP1GczPWUJtGdwfZiZr2yRBj7Scyk1s8wNaFUtTshlEhBYLEJjqfYJABi87WkeuXdcvmmkXsRGptFgOfnqJTS92YUVSXHQDDeXzdrq-qqxOuvonS18-mov-yHm6Jn-Ks1JtSt1P9u65k7IsfAswwXuPsA4YX=w895-h599-s-no-gm?authuser=0\" \n      class=\"restaurant-image\"\n    />\n    <div class=\"overlay-text\">\n      Bienvenidos al Restaurante Hotel Guadiana\n    </div>\n  </div>\n\n  <footer>\n    <p>© 2025 Restaurante Hotel Guadiana</p>\n  </footer>\n</body>\n",
